{
  "name": "PACE (Pharmaceutical Assistance Contract for the Elderly)",
  "eligibility": {
    "age": 65,
    "income_limits": "PACE: Single person ≤ $14,500; Married couple ≤ $17,700 (based on previous calendar year gross income). Note: PACENET (companion program) for higher incomes: Single $14,501–$33,500; Married $17,701–$41,500.[1][3][4][6]",
    "asset_limits": "No asset limits or test; assets are not counted.[7]",
    "other_requirements": [
      "Pennsylvania resident for at least 90 consecutive days prior to application.[1][3][4]",
      "Not eligible for or enrolled in Medicaid pharmaceutical benefits (Department of Human Services' Medical Assistance prescription benefit).[1][3][4][6]",
      "Income includes: Gross Social Security/SSI (excluding Medicare premiums), pensions, wages, self-employment, alimony, annuities/IRAs, unemployment, interest/dividends, net rental, etc. Excludes: Medicare Part B premiums, Property Tax/Rent Rebates, VA Aid and Attendance, SNAP, LIHEAP, federal stimulus, etc.[5][7]"
    ]
  },
  "benefits": {
    "type": "financial",
    "value": "Pays for prescription drugs with co-payments: Generic $6 per Rx, Brand-name $9 per Rx. No monthly premium or fee.[6]",
    "varies_by": "program_tier (PACE vs PACENET; PACENET has higher copays: Generic $8, Brand $15; monthly premium ~$37.45)[6]"
  },
  "application": {
    "methods": [
      "Phone: 1-800-225-7223 (PACE hotline).[5]",
      "Website: https://pacecares.magellanhealth.com/.[5]",
      "PA MEDI helpline: 1-800-783-7067 for local assistance and application help.[5]"
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["No specific form name/number listed; apply via hotline or website.[5]"],
    "documents": [
      "Proof of age, residency (90 days), previous year income verification (e.g., Social Security statements, tax returns, pay stubs).[7]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide to eligible PA residents.[1][4][8]",
    "regional_variations": null,
    "offices_or_providers": []
  },
  "official_source": "https://www.pa.gov/agencies/aging/aging-programs-and-services/pace-program[8]",
  "gotchas": [
    "Eligibility based strictly on previous calendar year's income (e.g., 2025 income for 2026 applications).[3][4][5]",
    "Excludes those with any Medicaid prescription coverage, even if partial; Medicare Savings Program (Part B premium help only) may still qualify.[5]",
    "Income calculation specifics matter: Includes spouse's income if living together, gifts/inheritances over $300, but excludes many rebates/aid payments.[7]",
    "No automatic annual income limit adjustments; fixed by statute unless legislature acts.[6]",
    "Not the national PACE (Program of All-Inclusive Care for the Elderly) which is a different service for 55+ needing nursing home level care.[2]"
  ],
  "data_shape_notes": "Two-tier structure (PACE low-income no premium; PACENET higher-income with premium/copays); no assets test; income fixed by household type (single/married couple only, no larger household table); statewide with no regional variations; funded by PA Lottery."
}

{
  "name": "LIHEAP",
  "eligibility": {
    "age": null,
    "income_limits": "Gross annual household income at or below 150% of Federal Poverty Guidelines. For 2026-2027 (effective February 1, 2026): 1: $23,940; 2: $32,460; 3: $40,980; 4: $49,500; 5: $58,020; 6: $66,540; 7: $75,060; 8: $83,580; 9: $92,100; 10: $100,620. Add $8,520 per additional person. Includes all household members' income (related/unrelated roomers sharing expenses). Excludes: educational grants/loans (unless for basic living), home produce for consumption, Senior Citizen Rebate, work/training incentives.",
    "asset_limits": "No asset or resource limits.",
    "other_requirements": ["Household includes all living together sharing expenses (children, relatives, unrelated roomers).", "Renters and homeowners eligible.", "No requirement for public assistance, unpaid bills, or SSN (but affidavit needed for household members 1+ without SSN)."]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time cash grant of $200-$1,000 paid directly to utility/fuel provider. Varies by household size, income, fuel type, and county (use DHS Benefit Amount Table tool for exacts). Crisis grants for households in immediate danger of no heat.",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online: COMPASS at https://www.pa.gov/services/dhs/apply-for-the-low-income-home-energy-assistance-program-liheap", "In-person: Local County Assistance Office (locations via county list)", "Phone/mail: Contact local County Assistance Office"],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["LIHEAP application (includes Energy Assistance Affidavit for those without SSN)", "Apply via COMPASS online tool"],
    "documents": ["Names, birthdates, SSNs (or affidavit) for all household members", "Proof of income for all household members", "Most recent utility bill"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Benefit amounts vary by county and fuel type (use DHS Benefit Amount Table). Administered via local County Assistance Offices with potential differences in processing.",
    "offices_or_providers": ["County Assistance Offices (statewide list available)"]
  },
  "official_source": "https://www.pa.gov/agencies/dhs/resources/liheap",
  "gotchas": ["Seasonal: Applications Dec 3, 2025-May 8, 2026 only.", "No repayment, but one-time grant per season.", "Income excludes specific items like educational aid—verify exclusions.", "Crisis grants separate for shut-off risk.", "Benefits county/fuel-specific—check table.", "Older data (e.g., 2019-2022 limits) outdated; use current 2026 figures."],
  "data_shape_notes": "Income at fixed 150% FPL table by household size; no assets; benefits scale by household size, income range, county, fuel type via lookup table; seasonal with crisis tier; county-administered"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Household income no more than 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are not specified in sources; contact local provider for current table (e.g., for 2025-2026, check HHS poverty guidelines).",
    "asset_limits": null,
    "other_requirements": ["Unemployed", "Live in Pennsylvania (often limited to specific counties served by local providers)", "Authorized to work in the United States"]
  },
  "benefits": {
    "type": "employment",
    "value": "On-the-job training at community-based nonprofit and public sites (e.g., senior centers, schools, hospitals, daycare); average 20 hours per week (or 20 hours/week or 40 hours every two weeks); paid stipend at the highest of federal, state, or local minimum wage; serves as bridge to unsubsidized employment; typically lasts about 6 months.",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local providers (e.g., Philadelphia: (215) 686-8450 or participant interest form at phila.gov/programs/senior-community-service-employment-program-scsep/; Westmoreland: 724-925-4084; statewide info: pa.gov/services/aging/apply-for-the-senior-community-service-employment-program)", "In-person at local offices (e.g., Crispus Attucks in York County)", "Online interest form for some regions (Philadelphia)"],
    "processing_time": null,
    "waitlist": "Possible due to funding limits; varies by region and demand (not specified)",
    "forms": ["Participant interest form (Philadelphia); general application at local SCSEP offices"],
    "documents": ["State or Federal picture ID", "Social Security card", "Proof of all income sources (e.g., Social Security award letter, unemployment determination)", "Proof of residency", "Work authorization if applicable"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Administered by local grantees; serves specific counties (e.g., Philadelphia only in Philly; Westmoreland County; York/Adams Counties; not uniform across all PA counties)",
    "regional_variations": "Different local providers handle intake, placements, and contacts; e.g., Philadelphia requires living in Philly, Westmoreland serves county residents; hours may be phrased as 20/week or 40/2 weeks; wait times and availability vary by funding and slots.",
    "offices_or_providers": ["Philadelphia Office: (215) 686-8450", "Westmoreland County: Westmoreland County Community College, 724-925-4084", "York/Adams Counties: Crispus Attucks, York", "Statewide contact via pa.gov/aging"]
  },
  "official_source": "https://www.pa.gov/services/aging/apply-for-the-senior-community-service-employment-program",
  "gotchas": ["Not statewide—must contact county-specific provider; eligibility often county-restricted (e.g., can't apply in Philly if living elsewhere); income is 125% FPL (stricter than some programs); priority to veterans, over 65, disabled, rural, homeless—at-risk; temporary (max ~6-12 months, not permanent job); no asset limits mentioned but prove all income sources; funding fluctuations may cause waitlists."],
  "data_shape_notes": "County-restricted with multiple local providers; income at 125% FPL (contact for table); no asset test; benefits fixed at ~20 hours/week min wage but placements vary by region; priority tiers affect entry."
}

{
  "name": "Legal Counsel for the Elderly / Pennsylvania Legal Aid Network",
  "eligibility": {
    "age": 60,
    "income_limits": "Generally 125% of the Federal Poverty Guidelines (FPG), varying by household size and local program; exact 2026 figures not specified in sources but pegged to governmental guidelines (e.g., examples from related programs: individual ~$1,533-$1,916/month gross). Contact local program for current table as it increases with household size.[1][2][4]",
    "asset_limits": "Varies by local program; some have asset guidelines (e.g., $5,500-$9,000 for certain benefits programs, but specific to legal aid not detailed). Personal assets may affect qualification.[4][5]",
    "other_requirements": ["Pennsylvania resident", "Low-income with greatest economic/social needs prioritized", "Based on local program priorities and governmental guidelines"]
  },
  "benefits": {
    "type": "service",
    "value": "Civil legal assistance including abuse, age discrimination, guardianship defense, healthcare, housing, long-term care, Medicaid, Medicare, nutrition, Social Security/SSI, utilities. Provided by independent regional/specialized programs; no specific dollar amounts or hours stated.[2][7]",
    "varies_by": "priority_tier|region"
  },
  "application": {
    "methods": ["Online application at palegalaid.net (processed by county program)", "Phone: 1-800-322-7572 for referrals", "Direct to local program via palegalaid.net/find-legal-help (county filter)", "PALawHELP.org for info and referrals"],
    "processing_time": "Not specified",
    "waitlist": "High demand; nationally ~50% turned away due to resources, 80% of poor's legal needs unmet[1]",
    "forms": ["Application for Legal Services via palegalaid.net/apply"],
    "documents": ["Not explicitly listed; prepare income proof, household size details, asset info, legal problem description as eligibility screening requires these"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Serves every county in Pennsylvania",
    "regional_variations": "Delivered via 8 regional programs and 6 specialized programs; eligibility/priorities vary by local program[1][6][7]",
    "offices_or_providers": ["Locate via palegalaid.net providers page with county filter"]
  },
  "official_source": "https://palegalaid.net/ and https://www.pa.gov/services/aging/apply-for-the-older-pennsylvanians-legal-assistance-program",
  "gotchas": ["Income at 125% FPG general but local variations/priorities apply; exceptions possible for seniors/domestic violence but not guaranteed[1][4][5]", "High demand leads to turnaways; not all qualifiers served[1]", "Asset tests may apply beyond income; contact local program essential as no centralized exact limits[4][5]", "Focus on elderly 60+ with greatest needs, not automatic for all seniors[2]"],
  "data_shape_notes": "Network of independent regional/specialized programs with varying local guidelines/priorities; income pegged to 125% FPG but exact tables/assets/currents require local contact; elderly prioritized via Older Pennsylvanians Legal Assistance Program integration"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all regardless of financial status.",
    "asset_limits": "No asset limits; no financial eligibility requirements.",
    "other_requirements": ["Resides (or planning to reside) in a Pennsylvania long-term care facility such as nursing home, assisted living, personal care home, domiciliary care home, or adult day care center; or receives community-based long-term care services. Open to residents, potential residents, families, friends, staff, or community members with concerns about quality of life, care, rights, or facility issues."][1][2][3][4][5][7]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free, confidential advocacy services including: investigating and resolving complaints (e.g., discharge/eviction, care quality, medications, staffing, finances, property loss, food, environment, rights, policies); routine unannounced facility visits; education on residents' rights and self-advocacy; referrals to long-term care programs; assistance with resident/family councils; mediation; support for those unable to self-advocate (via POA if needed). No financial aid, healthcare services, or fixed hours/dollars provided.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Local ombudsman programs (e.g., statewide via PA Department of Aging at (717) 783-8975; Philadelphia CARIE at 215-545-5724 or 610-860-5050; Center in the Park at 215-844-1829); county-specific (e.g., Franklin County, Lancaster, Montgomery); Online: pa.gov/services/aging/request-assistance-from-a-long-term-care-ombudsman; Email: ombudsman@carie.org (Philadelphia); In-person: Local offices or facilities; Mail: PA Department of Aging, Office of the State Long-Term Care Ombudsman, 555 Walnut Street, 5th Floor, Harrisburg, PA 17101."],
    "processing_time": "Immediate response to complaints; no formal processing as it's complaint-driven advocacy, not an enrollment program.",
    "waitlist": null,
    "forms": ["No specific forms required; contact directly to request assistance."],
    "documents": ["None required initially; may provide details on complaint, resident consent (if applicable), or POA documentation if resident cannot consent."][1][2][3][4][5][6][7][9]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services tied to long-term care facilities or community services within Pennsylvania; access via local/regional offices.",
    "regional_variations": "Administered locally by county Area Agencies on Aging or providers (e.g., Philadelphia: CARIE and Center in the Park; Franklin County; Lancaster County; Montgomery County); different contact points, volunteer involvement, and coverage areas, but standardized state-certified training and services.",
    "offices_or_providers": ["PA Department of Aging, 555 Walnut Street, 5th Floor, Harrisburg, PA 17101; county-specific like Franklin County Ombudsman, Lancaster County Office of Aging, PCA Philadelphia, CARIE Philadelphia, Center in the Park (NE/NW Philadelphia)."][1][2][3][6][8][9][10]
  },
  "official_source": "https://www.pa.gov/agencies/aging/aging-programs-and-services/advocacy-education-protection",
  "gotchas": ["Not a direct service provider or financial aid program—purely advocacy for complaints and rights; requires resident permission to discuss with staff (confidentiality protected); not for non-long-term care settings; families can contact on behalf of loved ones but ombudsman prioritizes resident's wishes; people mistake it for admission/placement help rather than issue resolution; volunteer/staff availability may vary locally."][1][2][3][4][5][6][7],
  "data_shape_notes": "no income test; complaint-driven advocacy, not enrollment-based; regionally administered statewide with local providers; open to all in long-term care without eligibility barriers"
}

{
  "name": "APPRISE Insurance Counseling Program (now PA MEDI)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries[1][4][6]",
    "asset_limits": "No asset limits; no financial eligibility requirements[1][4][6]",
    "other_requirements": ["Must be a Medicare beneficiary (typically age 65+ or under 65 with certain disabilities)[6][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one confidential counseling on Medicare Parts A/B/D, Medicare Advantage, Medigap, long-term care insurance, Medicare Savings Programs (QMB/SLMB/QI), prescription assistance (PACE/PACENET), Medicaid, appeals, claims, plan comparisons, referrals, printed materials, group presentations, and eligibility screening for other programs[1][2][3][4][5][6][7][9]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Statewide 1-800-783-7067[5]", "Local Area Agency on Aging contacts (e.g., Franklin County: 717-263-2153[2]; Greene/Fayette/Washington: 1-888-300-2704[4]; Wesley Family Services: 412-661-1438[6])", "In-person or phone/email via local providers[6][10]", "Contact Pennsylvania Department of Aging for local office[8]"],
    "processing_time": "Appointments available upon contact; no formal processing as it's counseling, not benefits enrollment[1][2]",
    "waitlist": null,
    "forms": ["No specific forms required for counseling; counselors assist with applications for related programs like Medicare Savings or Extra Help[4][9]"],
    "documents": ["No documents needed for initial counseling; bring Medicare card/ID for detailed assistance or applications[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Medicare beneficiaries residing in Pennsylvania[1][6][8]",
    "regional_variations": "Delivered locally through 52 Area Agencies on Aging with trained staff/volunteers; contact methods, sites, and coordinators vary by county (e.g., Franklin, Cumberland, Lehigh, Greene/Fayette/Washington)[2][3][4][7][10]",
    "offices_or_providers": ["Pennsylvania Department of Aging statewide[8]", "Local Area Agencies on Aging (e.g., Franklin County Area Agency on Aging[2], SWPA AAA[4], Wesley Family Services[6], Lehigh County[10])"]
  },
  "official_source": "https://www.pa.gov/agencies/aging/aging-programs-and-services/pa-medi-medicare-counseling[8]",
  "gotchas": ["Program rebranded to PA MEDI effective July 1, 2021 – same services, new name; still referred to as APPRISE in some areas[4][6][9]", "Not a direct benefits provider – offers counseling and assistance only, underutilized despite high value (e.g., $494k saved in one county[2])", "Services free/confidential but requires contacting local agency; no online self-scheduling statewide[1]", "Helps with but does not guarantee enrollment in savings programs which have strict income/asset limits (e.g., QMB: $1,325/mo single[5])"],
  "data_shape_notes": "no income/asset test for counseling; statewide via 52 local Area Agencies on Aging with volunteer support; rebranded to PA MEDI but legacy APPRISE name persists regionally"
}
